export async function sendEmail({
  mode = "file",
  emailMessage,
  outPath = null,
  sendmailPath = "sendmail",
  to = null,
  subject = null,
  textBody = null,
  htmlBody = null,
  immCliPath = null,
  pythonBin = "python3",
  env = undefined,
}) {
  if (mode === "file") {
    if (!outPath) {
      throw new Error("Email file delivery requires --email-out.");
    }

    await writeOutputFile(outPath, emailMessage);
    return { mode: "file", outPath };
  }

  if (mode === "sendmail") {
    await execFileAsync(sendmailPath, ["-t", "-i"], { input: emailMessage, env });
    return { mode: "sendmail" };
  }

  if (mode === "imm-romania") {
    if (!immCliPath) {
      throw new Error("IMM-Romania delivery requires --imm-cli.");
    }
    if (!to || !subject) {
      throw new Error("IMM-Romania delivery requires recipient and subject.");
    }

    const body = htmlBody || textBody;
    if (!body) {
      throw new Error("IMM-Romania delivery requires a body.");
    }

    const args = [immCliPath, "mail", "send", "--to", to, "--subject", subject, "--body", body];
    if (htmlBody) {
      args.push("--html");
    }

    await execFileAsync(pythonBin, args, { env });
    return { mode: "imm-romania", cli: immCliPath };
  }

  throw new Error(`Unsupported email delivery mode: ${mode}`);
}

function escapeHeader(value) {
